-- Vergelijkt match_kickoffs.kickoff met de juiste waarden uit index.html (MATCHES array)
-- Toont enkel rijen die NIET overeenkomen (mismatches). Gebruikt json_each (geen UNION-limiet).
WITH correct(match_id, correct_kickoff) AS (
  SELECT json_extract(j.value,'$.id'), CAST(json_extract(j.value,'$.ko') AS INTEGER)
  FROM json_each('[{"id":"m1","ko":1781204400000},{"id":"m2","ko":1781229600000},{"id":"m3","ko":1781290800000},{"id":"m4","ko":1781312400000},{"id":"m5","ko":1781377200000},{"id":"m6","ko":1781388000000},{"id":"m7","ko":1781398800000},{"id":"m8","ko":1781409600000},{"id":"m9","ko":1781456400000},{"id":"m10","ko":1781467200000},{"id":"m11","ko":1781478000000},{"id":"m12","ko":1781488800000},{"id":"m13","ko":1781539200000},{"id":"m14","ko":1781550000000},{"id":"m15","ko":1781560800000},{"id":"m16","ko":1781571600000},{"id":"m17","ko":1781636400000},{"id":"m18","ko":1781647200000},{"id":"m19","ko":1781658000000},{"id":"m20","ko":1781668800000},{"id":"m21","ko":1781715600000},{"id":"m22","ko":1781726400000},{"id":"m23","ko":1781737200000},{"id":"m24","ko":1781748000000},{"id":"m25","ko":1781798400000},{"id":"m26","ko":1781820000000},{"id":"m27","ko":1781827200000},{"id":"m28","ko":1781830800000},{"id":"m29","ko":1781906400000},{"id":"m30","ko":1781895600000},{"id":"m31","ko":1781917200000},{"id":"m32","ko":1781928000000},{"id":"m33","ko":1781974800000},{"id":"m34","ko":1781982000000},{"id":"m35","ko":1782000000000},{"id":"m36","ko":1782014400000},{"id":"m37","ko":1782057600000},{"id":"m38","ko":1782079200000},{"id":"m39","ko":1782079200000},{"id":"m40","ko":1782090000000},{"id":"m41","ko":1782147600000},{"id":"m42","ko":1782162000000},{"id":"m43","ko":1782172800000},{"id":"m44","ko":1782183600000},{"id":"m45","ko":1782234000000},{"id":"m46","ko":1782241200000},{"id":"m47","ko":1782255600000},{"id":"m48","ko":1782266400000},{"id":"m49","ko":1782338400000},{"id":"m50","ko":1782338400000},{"id":"m51","ko":1782338400000},{"id":"m52","ko":1782338400000},{"id":"m53","ko":1782349200000},{"id":"m54","ko":1782349200000},{"id":"m55","ko":1782414000000},{"id":"m56","ko":1782414000000},{"id":"m57","ko":1782428400000},{"id":"m58","ko":1782428400000},{"id":"m59","ko":1782439200000},{"id":"m60","ko":1782439200000},{"id":"m61","ko":1782500400000},{"id":"m62","ko":1782500400000},{"id":"m63","ko":1782518400000},{"id":"m64","ko":1782518400000},{"id":"m65","ko":1782529200000},{"id":"m66","ko":1782529200000},{"id":"m67","ko":1782597600000},{"id":"m68","ko":1782597600000},{"id":"m69","ko":1782606600000},{"id":"m70","ko":1782606600000},{"id":"m71","ko":1782612000000},{"id":"m72","ko":1782612000000},{"id":"m73","ko":1782673200000},{"id":"m74","ko":1782752400000},{"id":"m75","ko":1782765000000},{"id":"m76","ko":1782781200000},{"id":"m77","ko":1782838800000},{"id":"m78","ko":1782853200000},{"id":"m79","ko":1782867600000},{"id":"m80","ko":1782921600000},{"id":"m81","ko":1782936000000},{"id":"m82","ko":1782950400000},{"id":"m83","ko":1783018800000},{"id":"m84","ko":1783033200000},{"id":"m85","ko":1783047600000},{"id":"m86","ko":1783105200000},{"id":"m87","ko":1783123200000},{"id":"m88","ko":1783135800000},{"id":"m89","ko":1783184400000},{"id":"m90","ko":1783198800000},{"id":"m91","ko":1783281600000},{"id":"m92","ko":1783296000000},{"id":"m93","ko":1783364400000},{"id":"m94","ko":1783382400000},{"id":"m95","ko":1783440000000},{"id":"m96","ko":1783461600000},{"id":"m97","ko":1783627200000},{"id":"m98","ko":1783710000000},{"id":"m99","ko":1783803600000},{"id":"m100","ko":1783818000000},{"id":"m101","ko":1784055600000},{"id":"m102","ko":1784142000000},{"id":"m103","ko":1784408400000},{"id":"m104","ko":1784487600000}]') AS j
)
SELECT
  mk.match_id,
  mk.kickoff                                   AS huidige_kickoff,
  c.correct_kickoff                            AS juiste_kickoff,
  datetime(mk.kickoff/1000,'unixepoch')        AS huidig_utc,
  datetime(c.correct_kickoff/1000,'unixepoch') AS juist_utc,
  ROUND((mk.kickoff - c.correct_kickoff)/3600000.0,2) AS verschil_uren
FROM match_kickoffs mk
JOIN correct c ON c.match_id = mk.match_id
WHERE mk.kickoff <> c.correct_kickoff
ORDER BY CAST(SUBSTR(mk.match_id,2) AS INTEGER);
